// onKeyDown fires before the value changes — good for blocking characters
function NumberInput() {
  const handleKeyDown = e => {
    // Allow: digits, Backspace, Delete, Tab, arrows, Enter
    const allowed = /[0-9]/.test(e.key) ||
      ['Backspace', 'Delete', 'Tab', 'Enter', 'ArrowLeft', 'ArrowRight'].includes(e.key);
    if (!allowed) {
      e.preventDefault(); // blocks the key before it reaches the input
    }
  };

  return <input type="text" onKeyDown={handleKeyDown} />;
}

// onKeyUp fires after — good for acting once per key press (not per repeat)
function SearchBox() {
  const [query, setQuery] = React.useState('');

  const handleKeyUp = e => {
    if (e.key === 'Escape') {
      setQuery(''); // clear after the key is released
    }
  };

  return (
    <input
      value={query}
      onChange={e => setQuery(e.target.value)}
      onKeyUp={handleKeyUp}
    />
  );
}

// event.key — use for text/meaning-based shortcuts
const handleKeyDown = e => {
  if (e.key === 'Enter') submitForm();
  if (e.key === 'Escape') closeModal();
};

// event.code — use for position-based game controls
const handleGameKey = e => {
  switch (e.code) {
    case 'KeyW': moveUp(); break;
    case 'KeyA': moveLeft(); break;
    case 'KeyS': moveDown(); break;
    case 'KeyD': moveRight(); break;
  }
  // Works the same on AZERTY (where 'W' key is at 'Z' position)
};

function RichEditor({ onSave, onUndo }) {
  const handleKeyDown = e => {
    // Cross-platform save: Ctrl+S (Windows/Linux) or Cmd+S (Mac)
    if ((e.ctrlKey || e.metaKey) && e.key === 's') {
      e.preventDefault(); // stop browser's Save Page dialog
      onSave();
      return;
    }
    // Undo
    if ((e.ctrlKey || e.metaKey) && e.key === 'z') {
      e.preventDefault();
      onUndo();
      return;
    }
    // Redo (Ctrl+Shift+Z or Ctrl+Y)
    if ((e.ctrlKey || e.metaKey) && e.shiftKey && e.key === 'z') {
      e.preventDefault();
      redo();
      return;
    }
    // Escape to blur / cancel
    if (e.key === 'Escape') {
      e.currentTarget.blur();
    }
  };

  return (
    <textarea
      onKeyDown={handleKeyDown}
      style={{ width: '100%', height: 200 }}
    />
  );
}

import { useEffect } from 'react';

// Global shortcut — '/' to focus search
function useGlobalShortcut(key, callback) {
  useEffect(() => {
    const handler = e => {
      // Ignore if focus is inside a text input
      const tag = document.activeElement?.tagName;
      if (['INPUT', 'TEXTAREA', 'SELECT'].includes(tag)) return;
      if (e.key === key) callback(e);
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [key, callback]);
}

function Navbar() {
  const searchRef = React.useRef(null);
  useGlobalShortcut('/', e => {
    e.preventDefault();
    searchRef.current?.focus();
  });
  return <input ref={searchRef} placeholder="Search (press /)" />;
}

// Non-focusable div — needs tabIndex to receive keyboard events
function InteractiveCard({ onSelect }) {
  return (
    <div
      tabIndex={0}  // makes the div focusable
      role="button"  // accessibility
      onKeyDown={e => {
        if (e.key === 'Enter' || e.key === ' ') onSelect();
      }}
    >
      Select me with keyboard
    </div>
  );
}

import { useState } from 'react';

function TagInput() {
  const [tags, setTags] = useState([]);
  const [value, setValue] = useState('');

  const handleKeyDown = e => {
    if (e.key === 'Enter' && value.trim()) {
      e.preventDefault(); // stop form submit
      setTags(prev => [...prev, value.trim()]);
      setValue('');
    }

    if (e.key === 'Backspace' && value === '' && tags.length > 0) {
      // Remove last tag when input is empty
      setTags(prev => prev.slice(0, -1));
    }

    if (e.key === ',') {
      // Also add on comma
      e.preventDefault();
      if (value.trim()) {
        setTags(prev => [...prev, value.trim()]);
        setValue('');
      }
    }
  };

  return (
    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 4, border: '1px solid #d1d5db', padding: 4 }}>
      {tags.map((tag, i) => (
        <span key={i} style={{ background: '#dbeafe', padding: '2px 8px', borderRadius: 4 }}>
          {tag}
          <button onClick={() => setTags(prev => prev.filter((_, j) => j !== i))}>×</button>
        </span>
      ))}
      <input
        value={value}
        onChange={e => setValue(e.target.value)}
        onKeyDown={handleKeyDown}
        placeholder="Add tag…"
        style={{ border: 'none', outline: 'none', flexGrow: 1 }}
      />
    </div>
  );
}

import { useState } from 'react';

const ITEMS = ['Apple', 'Banana', 'Cherry', 'Date', 'Elderberry'];

function KeyboardList() {
  const [activeIndex, setActiveIndex] = useState(0);

  const handleKeyDown = e => {
    if (e.key === 'ArrowDown') {
      e.preventDefault(); // don't scroll the page
      setActiveIndex(i => Math.min(i + 1, ITEMS.length - 1));
    }
    if (e.key === 'ArrowUp') {
      e.preventDefault();
      setActiveIndex(i => Math.max(i - 1, 0));
    }
    if (e.key === 'Home') {
      e.preventDefault();
      setActiveIndex(0);
    }
    if (e.key === 'End') {
      e.preventDefault();
      setActiveIndex(ITEMS.length - 1);
    }
    if (e.key === 'Enter') {
      console.log('selected:', ITEMS[activeIndex]);
    }
  };

  return (
    <ul
      role="listbox"
      tabIndex={0}  // the list itself is the focus target
      onKeyDown={handleKeyDown}
      style={{ listStyle: 'none', padding: 0, outline: 'none' }}
    >
      {ITEMS.map((item, i) => (
        <li
          key={item}
          role="option"
          aria-selected={i === activeIndex}
          style={{
            padding: '8px 12px',
            background: i === activeIndex ? '#dbeafe' : 'transparent',
            cursor: 'pointer',
          }}
          onClick={() => setActiveIndex(i)}
        >
          {item}
        </li>
      ))}
    </ul>
  );
}

import { useRef } from 'react';

function CompositionAwareInput({ onSubmit }) {
  const composingRef = useRef(false);

  return (
    <input
      onCompositionStart={() => { composingRef.current = true; }}
      onCompositionEnd={() => { composingRef.current = false; }}
      onKeyDown={e => {
        // Don't submit while the user is composing a CJK character
        if (e.key === 'Enter' && !composingRef.current) {
          onSubmit(e.currentTarget.value);
        }
      }}
    />
  );
}

import { render, screen, fireEvent } from '@testing-library/react';
import userEvent from '@testing-library/user-event';

test('Enter adds a tag', async () => {
  render(<TagInput />);
  const input = screen.getByPlaceholderText(/Add tag/i);

  // userEvent.type simulates real typing including Enter
  await userEvent.type(input, 'React{Enter}');
  expect(screen.getByText('React')).toBeInTheDocument();
  expect(input).toHaveValue(''); // input cleared
});

test('arrow keys move active index', () => {
  render(<KeyboardList />);
  const list = screen.getByRole('listbox');
  list.focus();

  // Initially first item is selected
  expect(screen.getByText('Apple').closest('[aria-selected]')).toHaveAttribute('aria-selected', 'true');

  // Press ArrowDown
  fireEvent.keyDown(list, { key: 'ArrowDown' });
  expect(screen.getByText('Banana').closest('[aria-selected]')).toHaveAttribute('aria-selected', 'true');
});

test('Ctrl+S calls onSave', () => {
  const onSave = jest.fn();
  render(<RichEditor onSave={onSave} onUndo={jest.fn()} />);
  const textarea = screen.getByRole('textbox');

  fireEvent.keyDown(textarea, { key: 's', ctrlKey: true });
  expect(onSave).toHaveBeenCalledTimes(1);
});
